+fn parse_dtype_param(
+    primitive: Primitive,
+    key: &str,
+    params: &BTreeMap<String, String>,
+) -> Result<DType, EvalError> {
+    let raw = params.get(key).ok_or_else(|| EvalError::Unsupported {
