+const fn dtype_bit_width(dtype: DType) -> u32 {
+    match dtype {
+        DType::BF16 | DType::F16 => 16,
+        DType::F32 | DType::I32 | DType::U32 => 32,
+        DType::F64 | DType::I64 | DType::U64 | DType::Complex64 => 64,
+        DType::Complex128 => 128,
+        DType::Bool => 8,
+    }
+}
